@dataclass
class Thinking(AbstractCapability[Any]):
    """启用并配置模型思考/推理能力"""

    effort: ThinkingLevel = True
    """思考强度级别：True/False 或 'minimal'/'low'/'medium'/'high'/'xhigh'"""

    def get_model_settings(self) -> ModelSettings | None:
        return ModelSettings(thinking=self.effort)

@dataclass
class TimeoutWithRetry(AbstractCapability[Any]):
    """为模型请求添加超时和重试"""
    timeout: float = 30.0
    max_retries: int = 2

    async def wrap_model_request(
        self,
        ctx,
        *,
        request_context,
        handler,
    ) -> ModelResponse:
        last_error = None
        for attempt in range(self.max_retries + 1):
            try:
                return await asyncio.wait_for(
                    handler(request_context),
                    timeout=self.timeout,
                )
            except Exception as e:
                last_error = e
                if attempt == self.max_retries:
                    break
                await asyncio.sleep(1)
        raise last_error or Exception("Unknown error")

@dataclass
class CostTracker(AbstractCapability[Any]):
    """追踪并记录模型调用的 token 成本"""
    price_per_1k_input: float = 0.005
    price_per_1k_output: float = 0.015
    max_total_cost: float = 1.0

    def __post_init__(self):
        self.total_cost = 0.0
        self.request_costs = []

    async def after_model_request(self, ctx, *, response):
        cost = (
            response.usage.input_tokens * self.price_per_1k_input / 1000 +
            response.usage.output_tokens * self.price_per_1k_output / 1000
        )
        self.total_cost += cost
        self.request_costs.append({
            'step': ctx.run_step,
            'cost': cost,
            'tokens': response.usage.total_tokens,
        })

        if self.total_cost > self.max_total_cost:
            raise ModelRetry("成本超预算，请简化任务")
        return response
